import React from "react";
import { Link as LinkRouter } from "react-router-dom" 

export default function CardsCities({ cardFilter }) {
    return(
        <div>
        {cardFilter.map(city => (
            <div>
                <img src= {city.image} alt="hola" />
                <div>
                    <h2>{city.cityname}</h2>
                    <h3>{city.country}</h3>
                    <LinkRouter to={`citydetails/${city._id}`}>
                        See more
                    </LinkRouter>
                </div>
            </div>
        ))}
        </div>
    );
}
